package com.multilanglearner.data.network

import android.content.Context
import android.util.Log
import dagger.hilt.android.qualifiers.ApplicationContext
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import okhttp3.OkHttpClient
import okhttp3.Request
import java.io.File
import java.io.FileOutputStream
import java.util.concurrent.TimeUnit
import javax.inject.Inject
import javax.inject.Singleton

/**
 * Sherpa-ONNX 模型下载和管理服务
 *
 * 模型存储位置: context.filesDir/models/sherpa-onnx-whisper-base/
 * 模型文件:
 *   - base-encoder.int8.onnx (~40MB)
 *   - base-decoder.int8.onnx (~40MB)
 *   - base-tokens.txt (~1KB)
 */
@Singleton
class ModelManager @Inject constructor(
    @ApplicationContext private val context: Context
) {
    companion object {
        private const val TAG = "ModelManager"
        private const val MODEL_DIR_NAME = "sherpa-onnx-whisper-base"

        // Sherpa-ONNX 模型下载地址
        private const val BASE_URL = "https://github.com/k2-fsa/sherpa-onnx/releases/download/asr-models/"
        private const val ENCODER_FILE = "sherpa-onnx-whisper-base/base-encoder.int8.onnx"
        private const val DECODER_FILE = "sherpa-onnx-whisper-base/base-decoder.int8.onnx"
        private const val TOKENS_FILE = "sherpa-onnx-whisper-base/base-tokens.txt"

        // 本地文件名
        private const val LOCAL_ENCODER = "base-encoder.int8.onnx"
        private const val LOCAL_DECODER = "base-decoder.int8.onnx"
        private const val LOCAL_TOKENS = "base-tokens.txt"
    }

    private val client = OkHttpClient.Builder()
        .connectTimeout(30, TimeUnit.SECONDS)
        .readTimeout(600, TimeUnit.SECONDS)
        .followRedirects(true)
        .build()

    val modelDir: File get() = File(context.filesDir, "models/$MODEL_DIR_NAME")

    /**
     * 检查模型是否已下载
     */
    fun isModelDownloaded(): Boolean {
        val dir = modelDir
        return File(dir, LOCAL_ENCODER).exists() &&
               File(dir, LOCAL_DECODER).exists() &&
               File(dir, LOCAL_TOKENS).exists()
    }

    /**
     * 获取模型总大小（MB）
     */
    fun getModelSizeMB(): Double {
        if (!isModelDownloaded()) return 0.0
        return modelDir.walkTopDown()
            .filter { it.isFile }
            .map { it.length() }
            .sum() / 1024.0 / 1024.0
    }

    /**
     * 下载模型文件
     * @param onProgress (已下载字节, 总字节, 百分比, 当前文件名)
     * @return Result<Boolean> 下载结果
     */
    suspend fun downloadModel(
        onProgress: (Long, Long, Int, String) -> Unit = { _, _, _, _ -> }
    ): Result<Boolean> = withContext(Dispatchers.IO) {
        try {
            val dir = modelDir
            dir.mkdirs()

            val files = listOf(
                ENCODER_FILE to LOCAL_ENCODER,
                DECODER_FILE to LOCAL_DECODER,
                TOKENS_FILE to LOCAL_TOKENS
            )

            var totalDownloaded = 0L
            val estimatedTotal = 80 * 1024 * 1024L

            for ((remoteFile, localFile) in files) {
                val targetFile = File(dir, localFile)

                if (targetFile.exists() && targetFile.length() > 100) {
                    Log.d(TAG, "File already exists: $localFile")
                    totalDownloaded += targetFile.length()
                    continue
                }

                Log.d(TAG, "Downloading: $remoteFile")
                onProgress(totalDownloaded, estimatedTotal, (totalDownloaded * 100 / estimatedTotal).toInt(), localFile)

                val url = BASE_URL + remoteFile
                val request = Request.Builder().url(url).build()
                val response = client.newCall(request).execute()

                if (!response.isSuccessful) {
                    Log.e(TAG, "Download failed: ${response.code}")
                    return@withContext Result.failure(Exception("下载失败: $remoteFile (HTTP ${response.code})"))
                }

                val body = response.body ?: return@withContext Result.failure(Exception("空响应: $remoteFile"))
                val tempFile = File(dir, "$localFile.tmp")

                body.byteStream().use { input ->
                    FileOutputStream(tempFile).use { output ->
                        val buffer = ByteArray(8192)
                        var bytesRead: Int

                        while (input.read(buffer).also { bytesRead = it } != -1) {
                            output.write(buffer, 0, bytesRead)
                            totalDownloaded += bytesRead

                            val percent = (totalDownloaded * 100 / estimatedTotal).toInt().coerceAtMost(99)
                            onProgress(totalDownloaded, estimatedTotal, percent, localFile)
                        }
                    }
                }

                tempFile.renameTo(targetFile)
                Log.d(TAG, "Downloaded: $localFile")
            }

            onProgress(totalDownloaded, totalDownloaded, 100, "完成")
            Log.d(TAG, "All model files downloaded")
            Result.success(true)

        } catch (e: Exception) {
            Log.e(TAG, "Download failed", e)
            Result.failure(e)
        }
    }

    /**
     * 删除模型文件
     */
    fun deleteModel(): Boolean {
        return try {
            modelDir.deleteRecursively()
        } catch (e: Exception) {
            Log.e(TAG, "Failed to delete model", e)
            false
        }
    }
}
```

